// Final Email Compiler - All data available in single object
const allData = $json;

try {
  // All data is now merged in the single input object
  const dateInfo = {
    today: allData.today || 'Today',
    dayOfWeek: allData.dayOfWeek || 'Today',
    theme: allData.theme || 'Prayer'
  };

  const saintData = allData.saint || {
    name: 'Daily Saint',
    intro: 'Saint information unavailable'
  };

  const readingsData = allData.readings || {
    firstReading: 'Scripture reading',
    gospel: 'Gospel reading',
    psalm: 'Psalm',
    usccbLink: 'https://bible.usccb.org'
  };

  const mlbData = allData.mlb || {
    record: 'Information unavailable',
    gameUrl: 'https://www.mlb.com/dodgers'
  };

  // Get AI data from the previous node
  const aiInput = $input.all();
  const aiData = aiInput[0]?.json || {};

  // Parse AI spiritual content
  let spiritual = {};
  try {
    const aiText = aiData?.text || aiData?.message || aiData?.output || '';

    if (aiText) {
      const cleanText = aiText.replace(/```json\n?/g, "").replace(/```\n?/g, "").trim();
      spiritual = JSON.parse(cleanText);
      console.log('Successfully parsed AI spiritual content');
    } else {
      throw new Error('No AI content available');
    }
  } catch (parseError) {
    console.log('Using fallback spiritual content:', parseError.message);
    spiritual = {
      readingsContext: [{reading: "Scripture", reference: "See USCCB", historicalContext: "Historical context unavailable", catholicInterpretation: "Catholic interpretation unavailable"}],
      saintIntro: saintData.intro || 'Saint information available in database',
      reflection: `Today's theme is ${dateInfo.theme}. Take time to reflect on this Benedictine virtue.`,
      challenge: 'Spend 10 minutes in silent prayer today, listening for God\'s voice.',
      prayer: 'Lord, help us follow the example of the saints and grow in holiness. Amen.',
      historicalFacts: [{year: "2024", fact: "Historical facts unavailable"}]
    };
  }

  // Ensure prayer exists and is a string
  if (!spiritual.prayer || typeof spiritual.prayer !== 'string') {
    spiritual.prayer = 'Lord, bless this day and help us grow closer to You. Amen.';
  }

  // Format the subject line
  const subject = `Daily Reflection - ${dateInfo.today}`;

  // Build the comprehensive HTML email
  const html = `
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${subject}</title>
</head>
<body style="margin: 0; padding: 0; font-family: Georgia, 'Times New Roman', serif; background-color: #f5f5f0;">
  <div style="max-width: 600px; margin: 0 auto; background-color: #ffffff; box-shadow: 0 0 20px rgba(0,0,0,0.1);">

    <!-- Header -->
    <div style="background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); color: white; padding: 30px 20px; text-align: center;">
      <h1 style="margin: 0; font-size: 28px; font-weight: normal; letter-spacing: 1px;">Daily Reflection</h1>
      <p style="margin: 10px 0 0 0; font-size: 18px; opacity: 0.95;">${dateInfo.today}</p>
      <p style="margin: 5px 0 0 0; font-size: 14px; opacity: 0.9;">Theme: ${dateInfo.theme}</p>
    </div>

    <!-- Main Content -->
    <div style="padding: 30px 25px;">

      <!-- Saint of the Day -->
      ${saintData.name !== 'Weekday in Ordinary Time' ? `
      <div style="margin-bottom: 35px;">
        <h2 style="color: #4a5568; font-size: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 8px; margin-bottom: 15px;">
          ✝️ Saint of the Day
        </h2>
        <div style="background-color: #fef5e7; border-radius: 8px; padding: 15px;">
          <h3 style="margin: 0 0 10px 0; color: #764ba2; font-size: 18px;">${saintData.name}</h3>
          <p style="margin: 0 0 12px 0; color: #4a5568; line-height: 1.7; font-size: 14px;">
            ${spiritual.saintIntro || saintData.intro}
          </p>
          ${saintData.quote ? `<p style="margin: 0 0 12px 0; color: #553c9a; font-style: italic; font-size: 14px;">"${saintData.quote}"</p>` : ''}
        </div>
      </div>
      ` : ''}

      <!-- Readings Section -->
      <div style="margin-bottom: 35px;">
        <h2 style="color: #4a5568; font-size: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 8px; margin-bottom: 15px;">
          📖 Today's Readings
        </h2>
        <div style="background-color: #f7fafc; border-radius: 8px; padding: 20px;">
          <ul style="margin: 0; padding: 0; list-style: none;">
            <li style="margin-bottom: 12px; color: #4a5568; font-size: 16px;">
              <strong style="color: #2d3748;">First Reading:</strong> ${readingsData.firstReading}
            </li>
            <li style="margin-bottom: 12px; color: #4a5568; font-size: 16px;">
              <strong style="color: #2d3748;">Responsorial Psalm:</strong> ${readingsData.psalm}
            </li>
            ${readingsData.secondReading ? `
            <li style="margin-bottom: 12px; color: #4a5568; font-size: 16px;">
              <strong style="color: #2d3748;">Second Reading:</strong> ${readingsData.secondReading}
            </li>` : ''}
            <li style="margin-bottom: 0; color: #4a5568; font-size: 16px;">
              <strong style="color: #2d3748;">Gospel:</strong> ${readingsData.gospel}
            </li>
          </ul>
        </div>

        <p style="margin-top: 20px; text-align: center;">
          <a href="${readingsData.usccbLink}" 
             style="display: inline-block; background-color: #667eea; color: white; padding: 12px 25px; border-radius: 6px; text-decoration: none; font-size: 16px; font-weight: 600;">
            Read Full Texts at USCCB.org →
          </a>
        </p>
      </div>

      <!-- Benedictine Reflection -->
      <div style="margin-bottom: 35px;">
        <h2 style="color: #4a5568; font-size: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 8px; margin-bottom: 15px;">
          🕊️ Benedictine Reflection: ${dateInfo.theme}
        </h2>
        <div style="background: linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%); border-radius: 8px; padding: 20px;">
          <p style="margin: 0 0 15px 0; color: #4a5568; line-height: 1.7; font-size: 14px;">
            ${spiritual.reflection}
          </p>
          <div style="background-color: rgba(255,255,255,0.7); border-radius: 6px; padding: 12px;">
            <h4 style="margin: 0 0 8px 0; color: #764ba2; font-size: 14px; text-transform: uppercase; letter-spacing: 1px;">
              Today's Challenge
            </h4>
            <p style="margin: 0; color: #4a5568; line-height: 1.6; font-size: 14px; font-weight: 500;">
              ${spiritual.challenge}
            </p>
          </div>
        </div>
      </div>

      <!-- Prayer -->
      <div style="margin-bottom: 35px;">
        <h2 style="color: #4a5568; font-size: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 8px; margin-bottom: 15px;">
          🙏 Prayer for Today
        </h2>
        <div style="text-align: center; padding: 20px; background-color: #faf5ff; border-radius: 8px;">
          <p style="margin: 0; color: #553c9a; line-height: 1.8; font-size: 15px; font-style: italic;">
            ${spiritual.prayer.replace(/\n/g, '<br/>')}
          </p>
        </div>
      </div>

      <!-- Historical Facts -->
      ${spiritual.historicalFacts && spiritual.historicalFacts.length > 0 ? `
      <div style="margin-bottom: 35px;">
        <h2 style="color: #4a5568; font-size: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 8px; margin-bottom: 15px;">
          📅 On This Day in History
        </h2>
        <ul style="margin: 0; padding: 0; list-style: none;">
          ${spiritual.historicalFacts.map(h => `
          <li style="margin-bottom: 10px; padding-left: 60px; position: relative; color: #4a5568; line-height: 1.6; font-size: 14px;">
            <span style="position: absolute; left: 0; color: #667eea; font-weight: bold; width: 50px;">${h.year}:</span>
            ${h.fact}
          </li>`).join('')}
        </ul>
      </div>
      ` : ''}

      <!-- Dodgers Update -->
      <div style="margin-bottom: 30px;">
        <h2 style="color: #4a5568; font-size: 20px; border-bottom: 2px solid #e2e8f0; padding-bottom: 8px; margin-bottom: 15px;">
          ⚾ Dodgers Update
        </h2>
        <div style="background: linear-gradient(135deg, #005a9c 0%, #003d6b 100%); color: white; border-radius: 8px; padding: 20px;">
          <div style="margin-bottom: 15px;">
            <h3 style="margin: 0 0 10px 0; font-size: 16px; opacity: 0.9;">Team Info</h3>
            <p style="margin: 0; font-size: 16px;">${mlbData.record}</p>
          </div>

          <div style="text-align: center; margin-top: 18px;">
            <a href="${mlbData.gameUrl}" 
               style="display: inline-block; background-color: white; color: #005a9c; padding: 10px 25px; border-radius: 25px; text-decoration: none; font-weight: 600; font-size: 14px;">
              View More →
            </a>
          </div>
        </div>
      </div>

    </div>

    <!-- Footer -->
    <div style="background-color: #f7fafc; padding: 25px; text-align: center; border-top: 1px solid #e2e8f0;">
      <p style="margin: 0; color: #718096; font-size: 16px; font-style: italic; line-height: 1.6;">
        "Always we begin again"<br/>
        <span style="font-size: 14px; font-style: normal;">- St. Benedict</span>
      </p>
      <p style="margin: 15px 0 0 0; color: #a0aec0; font-size: 12px;">
        Daily Reflection • Catholic Spirituality • Linear Clean
      </p>
    </div>

  </div>
</body>
</html>
`;

  console.log('Email compilation complete. Subject:', subject);

  return {
    subject: subject,
    html: html,
    text: subject
  };

} catch (error) {
  console.error('Email compilation error:', error.message);
  return {
    subject: 'Daily Reflection - Error',
    html: '<p>Error compiling daily reflection. Please check the workflow.</p>',
    text: 'Error compiling daily reflection'
  };
}
